CREATE PROC [dbo].[CREATE_CDNR] @FromDate datetime, @ToDate datetime AS DECLARE @GSTIN AS CHAR(16) DECLARE @HSNCODETablename AS CHAR(16) DECLARE @HSNCodeField AS CHAR(12) DECLARE @IMTableQry AS VARCHAR(500) DECLARE @GSTIMPLDATE as Datetime IF OBJECT_ID('dbo.CDNR','U') IS NOT NULL DROP TABLE CDNR IF OBJECT_ID('dbo.CDNR_Info','U') IS NOT NULL DROP TABLE CDNR_Info SELECT @GSTIN=Txt FROM SysParam WHERE ParamCode='LocalSTaxRegnNo' Select @GSTIMPLDATE = dt from SysParam where ParamCode = 'GSTImplementationDate' SELECT * INTO CDNR FROM ((SELECT CUST.LSTNo AS 'GSTIN/UIN of Recipients', STDBkREf.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STDBkREf.DocNo) AS 'Invoice/Advance Receipt Number', STDBkREf.DocDt AS 'Invoice/Advance Receipt date',STD.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STD.DocNo) AS 'Note/Refund Voucher Number', STD.DocDt AS 'Note/Refund Voucher Date','C' AS 'DocumentType', 'Sales Return' AS 'Reason For Issuing document',Cast(LEFT(CUST.LSTNo,2) as Varchar(64)) AS [Place of Supply], SUM(STD.DocEntNetValue) AS [Note/Refund Voucher Value],CAST((STD.stdTaxComp1Per + STD.stdTaxComp1Per) AS Decimal(10,2))  AS 'Rate',    CAST(SUM(STD.TaxAV1) AS Decimal(10,2)) AS 'Taxable Value', CAST(SUM((CASE WHEN LEFT(CUST.LSTNo,2)=LEFT(@GSTIN,2) THEN STD.TaxComp3 ELSE '' END)) AS Decimal(10,2))  AS 'CESS Amount',CASE WHEN STDBkREf.DocDt < @GSTIMPLDATE then 'Y' ELSE 'N' END AS 'Pre GST' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType INNER JOIN Customers CUST ON CUST.Code=STH.PartyId INNER JOIN StkTrnDtls STDBkREf ON STDBkREf.TrnCtrlNo=STD.BackRefCtrlNo AND STDBkREf.TrnType=STD.BackRefTrnType AND STDBkREf.EntSrlNo=STD.BackRefDocEntSrlNo WHERE ISNULL(CUST.LSTNO,'')<>'' AND   (STH.TrnType=1300 ) AND LEN(CUST.LSTNO)>2 AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=@GSTIMPLDATE GROUP BY STD.DocNoPrefix,STD.DocNo,STD.DocDt,CUST.LSTNO,STD.stdTaxComp1Per,STD.stdTaxComp2Per,STD.stdTaxComp3Per,STDBkREf.DocNoPrefix,STDBkREf.DocNo,STDBkREf.Docdt) UNION all (SELECT CUST.LSTNo AS 'GSTIN/UIN of Recipients',(SELECT S.PartyStkDocNo FROM StkTrnHdr AS S WHERE S.DocNoPrefix=STD.RefDocNoPrefix AND S.DocNo=STD.RefDocNo AND S.TrnType=STD.RefDocType) AS 'Invoice/Advance Receipt Number', (SELECT S.PartyStkDocDt FROM StkTrnHdr AS S WHERE S.DocNoPrefix=STD.RefDocNoPrefix AND S.DocNo=STD.RefDocNo AND S.TrnType=STD.RefDocType)AS 'Invoice/Advance Receipt date', STD.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STD.DocNo) AS 'Note/Refund Voucher Number',STD.DocDt AS 'Note/Refund Voucher Date','D' AS 'DocumentType','Purchase Return' AS 'Reason For Issuing document', Cast(LEFT(CUST.LSTNo,2) as Varchar(64)) AS [Place of Supply],Cast(STH.NetDocValue as Decimal(10,2))  AS [Note/Refund Voucher Value],CAST((case when ((isnull([CUST].SrcTaxType,'0') = '0') OR Cust.SrcTaxType = '') then (STD.stdTaxComp1Per + STD.stdTaxComp2Per) else STD.stdTaxComp1Per end) AS Decimal(10,2))  AS 'Rate', CAST(SUM(STH.NetDocvalue-STH.TotDocTax-STH.TotDocEntAftTaxAddons+STH.TotDocEntAftTaxDedns) AS Decimal(10,2)) AS 'Taxable Value',CAST(SUM((CASE WHEN LEFT(CUST.LSTNo,2)=LEFT(@GSTIN,2) THEN STD.TaxComp3 ELSE '' END)) AS Decimal(10,2))  AS 'CESS Amount', CASE WHEN (SELECT S.PartyStkDocDt FROM StkTrnHdr AS S WHERE S.DocNoPrefix=STD.RefDocNoPrefix AND S.DocNo=STD.RefDocNo AND S.TrnType=STD.RefDocType) < @GSTIMPLDATE then 'Y' ELSE 'N' END AS 'Pre GST' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType INNER JOIN (SELECT CODE, VendorLST as LSTNo,SrcTaxType  FROM VEndors) AS CUST ON CUST.Code=STH.PartyId WHERE ISNULL(CUST.LSTNO,'')<>'' AND   (STH.TrnType=2300 ) AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=@GSTIMPLDATE GROUP BY STD.DocNoPrefix, STD.DocNo, STD.DocDt, CUST.LSTNO, STD.stdTaxComp1Per, STD.stdTaxComp2Per, STD.stdTaxComp3Per, STH.NetDocValue, STD.RefDocNoPrefix, STD.RefDocNo, STD.RefDocType, [CUST].SrcTaxType ) Union all (SELECT CUST.LSTNo AS 'GSTIN/UIN of Recipients', Cast('' as varchar(15))  AS 'Invoice/Advance Receipt Number', Cast('' as varchar(15)) AS 'Invoice/Advance Receipt date', STD.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STD.DocNo) AS 'Note/Refund Voucher Number', STD.DocDt AS 'Note/Refund Voucher Date', 'C' AS 'DocumentType', 'Sales Return' AS 'Reason For Issuing document', Cast(LEFT(CUST.LSTNo,2) as Varchar(64)) AS [Place of Supply], SUM(STD.DocEntNetValue) AS [Note/Refund Voucher Value], CAST((STD.stdTaxComp1Per + STD.stdTaxComp1Per) AS Decimal(10,2))  AS 'Rate', CAST(SUM(STD.TaxAV1) AS Decimal(10,2)) AS 'Taxable Value', CAST(SUM((CASE WHEN LEFT(CUST.LSTNo,2)=LEFT(@GSTIN,2) THEN STD.TaxComp3 ELSE '' END)) AS Decimal(10,2))  AS 'CESS Amount', 'N' AS 'Pre GST' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType INNER JOIN Customers CUST ON CUST.Code=STH.PartyId WHERE ISNULL(CUST.LSTNO,'')<>'' AND   (STH.TrnType=1300 ) AND LEN(CUST.LSTNO)>= 15 AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=@GSTIMPLDATE and STD.BackRefCtrlNo = 0 GROUP BY STD.DocNoPrefix, STD.DocNo,STD.DocDt,CUST.LSTNO,STD.stdTaxComp1Per,STD.stdTaxComp2Per,STD.stdTaxComp3Per)) AS CDNRTempTable UPDATE  CD set [Place of Supply] = Cast([Place of Supply] as Varchar(4)) + '-' + GL.Descr FROM CDNR CD Inner JOIN (SELECT Code,DEscr FROM GenLookUp WHERE RecID=92 ) GL on CD.[Place of Supply] = GL.Code SELECT COUNT(DISTINCT [GSTIN/UIN of Recipients]) AS [No. Of Recipients],COUNT(DISTINCT [Invoice/Advance Receipt Number]) AS [No. Of Invoices],COUNT(DISTINCT [Note/Refund Voucher Number]) AS [No. Of Notes/Vouchers],SUM([Note/Refund Voucher Value]) AS [Total Note/Refund Voucher value], SUM([Taxable Value]) AS [Total Taxable value],SUM([CESS AMOUNT]) AS [Total Cess] INTO CDNR_Info FROM CDNR IF OBJECT_ID('CDNR_Header','U') IS NULL CREATE TABLE CDNR_Header ([Summary For CDNR(9B)] Char(1) ) INSERT INTO InfoTable Values('CDNR',2,'<<Default>>','CDNR',4) 